import React from 'react';
import { useParams } from 'react-router-dom';
import { useBooks } from '../hooks/useBooks';
import { useCart } from '../hooks/useCart';

const BookDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { books } = useBooks();
  const { addToCart } = useCart();
  const book = books.find(b => b.id === id);

  if (!book) return <div>Book not found</div>;

  return (
    <div className="bg-white rounded-xl shadow-md p-6">
      <img src={book.image} alt={book.title} className="w-full h-64 object-cover rounded-md" />
      <h1 className="text-3xl font-bold mt-4">{book.title}</h1>
      <p className="text-gray-700 mt-2">{book.author}</p>
      <p className="text-gray-600 mt-4">{book.description}</p>
      <button onClick={() => addToCart(book)} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition mt-4">Add to Cart</button>
    </div>
  );
};

export default BookDetail;

