import React from 'react';
import { useCart } from '../hooks/useCart';
import { Link } from 'react-router-dom';

const Cart: React.FC = () => {
  const { cartItems, removeFromCart } = useCart();

  return (
    <div className="bg-white rounded-xl shadow-md p-6">
      <h1 className="text-2xl font-bold mb-4">Your Cart</h1>
      {cartItems.length === 0 ? (
        <p>Your cart is empty. <Link to="/books" className="text-blue-600 hover:text-blue-500 transition">Browse books</Link></p>
      ) : (
        <ul>
          {cartItems.map(item => (
            <li key={item.id} className="flex justify-between items-center py-2">
              <span>{item.title}</span>
              <button onClick={() => removeFromCart(item.id)} className="text-red-600 hover:text-red-500 transition">Remove</button>
            </li>
          ))}
        </ul>
      )}
      {cartItems.length > 0 && (
        <Link to="/checkout" className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition mt-4 inline-block">Proceed to Checkout</Link>
      )}
    </div>
  );
};

export default Cart;

