import React, { createContext, useState, ReactNode } from 'react';
import { Book } from '../types';

interface BookContextProps {
  books: Book[];
}

const initialBooks: Book[] = [
  { id: '1', title: 'The Great Gatsby', author: 'F. Scott Fitzgerald', description: 'A novel set in the Roaring Twenties.', image: 'https://images.unsplash.com/photo-1544717305-996b815c338c?w=400' },
  { id: '2', title: 'To Kill a Mockingbird', author: 'Harper Lee', description: 'A novel about racial injustice in the Deep South.', image: 'https://images.unsplash.com/photo-1544716278-ca5e3f4abd8c?w=400' },
  { id: '3', title: '1984', author: 'George Orwell', description: 'A dystopian novel about totalitarianism.', image: 'https://images.unsplash.com/photo-1544717305-996b815c338c?w=400' }
];

export const BookContext = createContext<BookContextProps>({ books: [] });

export const BookProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [books] = useState<Book[]>(initialBooks);

  return (
    <BookContext.Provider value={{ books }}>
      {children}
    </BookContext.Provider>
  );
};

